/**
 * @summary Verify a payment and confirm booking
 */
export const getVerifyPaymentUrl = (params: VerifyPaymentParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/payment/verify?${stringifiedParams}`
    : `/api/payment/verify`;
};

export const verifyPayment = async (
  params: VerifyPaymentParams,
  options?: RequestInit,
): Promise<PaymentVerifyResponse> => {
  return customFetch<PaymentVerifyResponse>(getVerifyPaymentUrl(params), {
    ...options,
    method: "GET",
  });
};

